+                LayoutDispatch {
+                    requested,
+                    selected: explicit,
+                    capability_unavailable: false,
+                    reason: "explicit_request_honored",
+                }
+            } else {
+                LayoutDispatch {
+                    requested,
+                    selected: preferred_layout_algorithm(ir),
+                    capability_unavailable: true,
+                    reason: "requested_algorithm_capability_unavailable_for_diagram_type",
+                }
+            }
